    </script>
    <title>PO Supplier</title>
</head>

<body style="width: 21cm;">

    <section class="bg-white" style="font-size: 10pt;">
        <div class="max-w-5xl mx-auto bg-white">
            <article class="overflow-hidden">
                <div class="bg-[white] rounded-b-md">
                    <div class="px-9">
                        <div class="space-y-6 text-slate-700">
                            <div class=" flex flex-row justify-between w-full items-center align-middle">

                                <img class="object-cover h-12 mt-4"
                                    src="data:image/jpeg;base64," />
                                    <svg id="barcode"
                                onload="JsBarcode(this, '{{$po_number}}', {height: 32, fontSize: 8});" class="mt-4 -mb-4"></svg>

                            </div>
                            <div class="w-full flex h-2">
                                <div class="bg-red-400 w-5/12 flex justify-end">

                                    <div class="w-8 right-0 bg-red-600"
                                        style="clip-path: polygon(0 0, 100% 0, 100% 100%, 25% 100%);">
                                        &nbsp;
                                    </div>

                                </div>
                                <div class="bg-red-600 w-7/12">&nbsp;</div>
                            </div>
                        </div>
                    </div>
                    <div class="px-9 pb-4 pt-0">
                        <div class="flex w-full pt-4 justify-center">
                            <h1 class="font-bold text-lg">Rincian PO #{{$po_number}}</h1>
                        </div>
                        <div class="flex w-full pt-4" style="font-size:10pt">
                            <table>
                                <tr>
                                    <td class="w-28">Nomor PO</td>
                                    <td class="px-2">:</td>
                                    <td>
                                        <span class="font-bold">{{$po_number}}</span>
                                    </td>
                                </tr>
                                <tr>
                                    <td>Tanggal</td>
                                    <td class="px-2">:</td>
                                    <td>
                                        <span>{{$date}}</span>
                                    </td>
                                </tr>
                                <tr>
                                    <td>Supplier</td>
                                    <td class="px-2">:</td>
                                    <td>
                                        <span>{{$supplier}}</span>
                                    </td>
                                </tr>
                                <tr>
                                    <td>Branch</td>
                                    <td class="px-2">:</td>
                                    <td>
                                        <span>{{$branch}}</span>
                                    </td>
                                </tr>
                            </table>
                        </div>
                    </div>


                    <div class="px-9">
                        <h3>Daftar Bahan</h3>
                        <table class="w-full">
                            <thead class="border-y border-gray-500 text-sm text-capitalize">
                                <tr class="text-left">
                                    <th class="px-2" width="2%">No</th>
                                    <th class="px-2" width="20%">Bahan</th>
                                    <th class="px-2" width="20%">Kategori Bahan</th>
                                    <th class="px-2 text-center" width="20%">Barcode</th>
                                    <th class="px-2" width="15%">Jumlah</th>
                                    <th class="px-2" width="15%">Satuan</th>
                                </tr>
                            </thead>
                            <tbody class="bg-white align-top text-xs">
                                @foreach ($ingredients as $key => $item)
                                <tr>
                                    <td class="py-1 px-2 border-biru-transparent">{{$key+1}}</td>
                                    <td class="py-1 px-2 border-biru-transparent">{{$item['ingredient']}}</td>
                                    <td class="py-1 px-2 border-biru-transparent">{{$item['brand']}}</td>
                                    <td class="px-2 border-biru-transparent text-center">
                                        @if($item['barcode'])
                                        <div class="flex justify-center">
                                            <svg id="barcode"
                                            onload="JsBarcode(this, '{{$item['barcode']}}', {height: 32, fontSize: 8, marginLeft: 0});"></svg>
                                        </div>
                                        @endif
                                    </td>
                                    <td class="py-1 px-2 border-biru-transparent">{{$item['qty']}}</td>
                                    <td class="py-1 px-2 border-biru-transparent">{{$item['unit']}}</td>
                                </tr>
                                @endforeach
                            </tbody>
                        </table>
                    </div>

                    <div class="p-9 uncut">
                        <p>
                            Demikian Detail Daftar Bahan yang harus dikirim maksimal sampai tanggal yang telah
                            ditentukan
                        </p>
                    </div>
                </div>
            </article>
        </div>
    </section>

</body>

</html>
